const __pageData = JSON.parse('{"title":"数据库测试：从单元到集成","description":"系统阐述数据库测试的形式化分类与隔离理论，深入探讨Prisma单元测试、TestContainers容器化集成测试、SQLite内存测试、迁移验证、工厂模式数据生成、性能基准测试及CI/CD中的数据库测试实践。","frontmatter":{"title":"数据库测试：从单元到集成","description":"系统阐述数据库测试的形式化分类与隔离理论，深入探讨Prisma单元测试、TestContainers容器化集成测试、SQLite内存测试、迁移验证、工厂模式数据生成、性能基准测试及CI/CD中的数据库测试实践。","date":"2026-05-01T00:00:00.000Z","tags":["数据库与ORM","测试","Prisma","TestContainers","Jest","Drizzle","pgbench","CI/CD","SQLite","Docker"],"category":"engineering"},"headers":[],"relativePath":"database-orm/10-database-testing.md","filePath":"database-orm/10-database-testing.md","lastUpdated":1777741461000}');
